generated_oml:
// ========================= // Physical Sensing Components
// =========================
instance SwingAngleEncoderSensor : DTDFVocab:SensingComponent [
    base:desc "Swing‑angle encoder measuring pendulum motion on the gantry crane"
    DTDFVocab:producedData SwingAngleEncoderDataTransmitted
]

instance AnemometerSensor : DTDFVocab:SensingComponent [
    base:desc "Anemometer measuring wind speed affecting crane dynamics"
    DTDFVocab:producedData AnemometerDataTransmitted
]

instance ArduinoMeasurementBoard : DTDFVocab:SensingComponent [
    base:desc "Arduino board that reads the swing‑angle encoder and anemometer and forwards data"
    DTDFVocab:producedData ArduinoBoardDataTransmitted
]

// =========================
// Physical‑to‑Virtual Data Transmission
// =========================
instance SwingAngleEncoderDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom SwingAngleEncoderSensor
]

instance AnemometerDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom AnemometerSensor
]

instance ArduinoBoardDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom ArduinoMeasurementBoard
]

// =========================
// Virtual Data Instances (time‑series)
// =========================
instance SwingAngleTimeSeriesData : DTDFVocab:Data [
    base:desc "Time‑stamped swing‑angle measurements stored in TimescaleDB"
    DTDFVocab:fromData SwingAngleEncoderDataTransmitted
    DTDFVocab:inputTo TimescaleDBEnabler
]

instance WindSpeedTimeSeriesData : DTDFVocab:Data [
    base:desc "Time‑stamped wind‑speed recordings stored in TimescaleDB"
    DTDFVocab:fromData AnemometerDataTransmitted
    DTDFVocab:inputTo TimescaleDBEnabler
]

instance SystemStateTimeSeriesData : DTDFVocab:Data [
    base:desc "Aggregated system state (sensor fusion) stored in TimescaleDB"
    DTDFVocab:fromData ArduinoBoardDataTransmitted
    DTDFVocab:inputTo TimescaleDBEnabler
]

// =========================
// Enablers (tools, platforms, containers)
// =========================
instance TimescaleDBEnabler : DTDFVocab:Enabler [
    base:desc "TimescaleDB instance used for time‑series storage"
    DTDFVocab:enables DataLoggingService
]

instance GrafanaEnabler : DTDFVocab:Enabler [
    base:desc "Grafana dashboard for visualizing telemetry"
    DTDFVocab:enables DataVisualizationService
]

instance MosquittoBrokerEnabler : DTDFVocab:Enabler [
    base:desc "Eclipse Mosquitto MQTT broker for inter‑service messaging"
    DTDFVocab:enables ContinuousValidationService
]

instance DockerContainerEnabler : DTDFVocab:Enabler [
    base:desc "Docker container runtime for all Python services"
    DTDFVocab:enables DataLoggingService,
              DataVisualizationService,
              TrajectoryGenerationService,
              PhysicsSimulationService,
              ContinuousValidationService,
              HumanMachineInterfaceService
]

instance GantryLibPythonModuleEnabler : DTDFVocab:Enabler [
    base:desc "Python 'gantrylib' module (pip installable) containing core algorithms"
    DTDFVocab:enables TrajectoryGenerationService,
              ContinuousValidationService,
              PhysicsSimulationService,
              HumanMachineInterfaceService
]

// =========================
// Services
// =========================
instance DataLoggingService : DTDFVocab:Service [
    base:desc "Service that continuously writes timestamped records into TimescaleDB"
    DTDFVocab:provides DataLoggingInsight
]

instance DataVisualizationService : DTDFVocab:Service [
    base:desc "Service that renders telemetry on Grafana dashboards"
    DTDFVocab:provides DataVisualizationInsight
]

instance TrajectoryGenerationService : DTDFVocab:Service [
    base:desc "Generates optimal, swing‑free trajectories using the kinematic model"
    DTDFVocab:provides OptimalTrajectoryInsight
]

instance PhysicsSimulationService : DTDFVocab:Service [
    base:desc "Runs a physics‑based simulation of the crane and its controllers"
    DTDFVocab:provides SimulationInsight
]

instance ContinuousValidationService : DTDFVocab:Service [
    base:desc "Continuously validates measured trajectories against simulated ones and raises alerts"
    DTDFVocab:provides DeviationAlertInsight,
              ThresholdExceededAlertInsight
]

instance HumanMachineInterfaceService : DTDFVocab:Service [
    base:desc "HMI for operator control, allowing manual interventions and re‑planning"
    DTDFVocab:provides OperatorInterventionAction,
              ReplanTaskAction
]

// =========================
// Insights & Actions
// =========================
instance DataLoggingInsight : DTDFVocab:Insight [
    base:desc "Confirmation that sensor data has been successfully persisted"
]

instance DataVisualizationInsight : DTDFVocab:Insight [
    base:desc "Real‑time visual representation of crane telemetry"
]

instance OptimalTrajectoryInsight : DTDFVocab:Insight [
    base:desc "Computed optimal, swing‑free trajectory for the current task"
]

instance SimulationInsight : DTDFVocab:Insight [
    base:desc "Result of the physics‑based simulation reflecting expected crane behavior"
]

instance DeviationAlertInsight : DTDFVocab:Insight [
    base:desc "Detection of deviation between measured and simulated trajectories"
]

instance ThresholdExceededAlertInsight : DTDFVocab:Insight [
    base:desc "Alert triggered when deviation metrics surpass configured thresholds"
]

instance OperatorInterventionAction : DTDFVocab:Action [
    base:desc "Operator manually intervenes to adjust crane operation"
    DTDFVocab:IsAutomatic false
]

instance ReplanTaskAction : DTDFVocab:Action [
    base:desc "Operator initiates a re‑planning of the crane task based on insights"
    DTDFVocab:IsAutomatic false
]

// =========================
// Models
// =========================
instance CADGeometryModel : DTDFVocab:Model [
    base:desc "CAD geometry of the gantry crane (Fusion 360) used for documentation"
    DTDFVocab:inputTo MkDocsEnabler
]

instance KinematicModel : DTDFVocab:Model [
    base:desc "Kinematic model employed by the Trajectory Generation Service"
    DTDFVocab:inputTo GantryLibPythonModuleEnabler
]

instance SimulationModel : DTDFVocab:Model [
    base:desc "Physics‑based simulation model of the crane and its controllers"
    DTDFVocab:inputTo GantryLibPythonModuleEnabler
]

// =========================
// Documentation Enabler (supporting model usage)
// =========================
instance MkDocsEnabler : DTDFVocab:Enabler [
    base:desc "MkDocs tool used to publish documentation of the CAD model"
]

// =========================
// Acting Components (actuators)
// =========================
instance CartStepperMotorActuator : DTDFVocab:ActingComponent [
    base:desc "Stepper motor driving the cart axis, controlled via Trinamic TMC4671‑Eval"
]

instance HoistStepperMotorActuator : DTDFVocab:ActingComponent [
    base:desc "Stepper motor driving the hoist axis, controlled via Trinamic TMC4671‑Eval"
]

instance ElectromagnetActuator : DTDFVocab:ActingComponent [
    base:desc "Electromagnet at the end of the hoist used to pick up pucks"
]

// =========================
// Environment (physical system)
// =========================
instance LabScaleGantryCraneEnvironment : DTDFVocab:Environment [
    base:contains SwingAngleEncoderSensor,
                 AnemometerSensor,
                 ArduinoMeasurementBoard,
                 CartStepperMotorActuator,
                 HoistStepperMotorActuator,
                 ElectromagnetActuator,
                 CADGeometryModel,
                 KinematicModel,
                 SimulationModel
]

// =========================
// Components (generic)
// =========================
instance GantryCraneFrameComponent : DTDFVocab:Component [
    base:desc "Structural frame of the lab‑scale gantry crane"
]

instance ControlSoftwareComponent : DTDFVocab:Component [
    base:desc "Python‑based controller software packaged as the 'gantrylib' module"
]

instance virtual_to_physical_interaction : DTDFVocab:VirtualToPhysical [
    base:desc "Digital twin services (e.g., the Trajectory Generator) publish command messages via MQTT; the Physical Crane Interface receives them, the Control Application translates the commands into motor set‑points sent to the Trinamic controllers, thus moving the cart, hoist and actuating the electromagnet."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "The twin is orchestrated as a set of Docker‑containerized services (TimescaleDB, MQTT broker, Grafana) together with Python applications (Physical Crane Interface, Control Application, Logging Application, Trajectory Generator, Simulation Service, Continuous Validation Service, Human‑Machine Interface) communicating primarily over MQTT and SQL, all running on a single host PC that is also directly connected to the physical crane."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "The digital twin spans the design stage (CAD models of the crane created in Autodesk Fusion 360), the manufacturing/assembly stage (physical frame, motors, sensors), and the operation stage (real‑time sensor data, trajectory execution, and validation)."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Continuous Validation Service continuously compares measured trajectories with simulated counterparts, computes distance metrics, and checks them against a predefined acceptable threshold; violations trigger operator alerts on the Grafana dashboard, providing quantitative fidelity assessment of the kinematic and simulation models."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Data exchange between PT and DT uses MQTT (Eclipse Mosquitto) for command and event signalling, and PostgreSQL/TimescaleDB over standard TCP/IP for time‑series storage; the Python Physical Crane Interface communicates with the Arduino via serial/USB."
]

instance dt_hosting_deployment : DTDFVocab:Deployment [
    base:desc "All twin services are deployed on a personal computer; the database, MQTT broker and Grafana dashboard are Docker containers started with a provided Docker‑Compose file; the remaining Python modules run natively on the host after installing the 'gantrylib' package."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "The exemplar follows several industry‑recognised standards and modeling approaches: C4 Model for architecture description, Capella Arcadia method for system modelling, MQTT (ISO/IEC 20922) as a standard messaging protocol, TimescaleDB built on the PostgreSQL standard, Docker container standards, and CAD data in Autodesk Fusion360 (widely supported format). These standards ensure interoperability and reproducibility of the digital twin components."
]
